} from './hooks/useSortableShotDropFeedback';
export type { DropOptions };

interface SortableShotItemProps {
  shot: Shot;
  onSelectShot: () => void;
  onDuplicateShot?: () => void;
  currentProjectId: string | null;
  isDragDisabled?: boolean;
  disabledReason?: string;
  shouldLoadImages?: boolean;
  shotIndex?: number;
  projectAspectRatio?: string;
  isHighlighted?: boolean;
  onGenerationDrop?: (shotId: string, data: GenerationDropData, options?: DropOptions) => Promise<void>;
  onFilesDrop?: (shotId: string, files: File[], options?: DropOptions) => Promise<void>;
  initialPendingUploads?: number;
  initialPendingBaselineNonVideoCount?: number;
  onInitialPendingUploadsConsumed?: () => void;
  dataTour?: string;
  finalVideo?: import('../hooks/useShotFinalVideos').ShotFinalVideo;
}

export const SortableShotItem: React.FC<SortableShotItemProps> = ({
  shot,
  onSelectShot,
  onDuplicateShot,
  currentProjectId,
  isDragDisabled = false,
  shouldLoadImages = true,
  shotIndex = 0,
  projectAspectRatio,
  isHighlighted = false,
  onGenerationDrop,
  onFilesDrop,
  initialPendingUploads = 0,
  initialPendingBaselineNonVideoCount,
  onInitialPendingUploadsConsumed,
  dataTour,
  finalVideo,
}) => {
  const {
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({
    id: shot.id,
    disabled: isDragDisabled,
  });

  const {
    isDropTarget,
    isOverWithoutPositionZone,
    withoutPositionDropState,
    withPositionDropState,
    pendingSkeletonCount,
    withoutPositionZoneRef,
    handleDragEnter,
    handleDragOver,
    handleDragLeave,
    handleDrop,
    handleWithoutPositionDrop,
    handleWithoutPositionDragEnter,
    handleWithoutPositionDragOver,
    handleWithoutPositionDragLeave,
  } = useSortableShotDropFeedback({
    shot,
    onGenerationDrop,
    onFilesDrop,
    initialPendingUploads,
    initialPendingBaselineNonVideoCount,
    onInitialPendingUploadsConsumed,
  });

  const style = isDragDisabled
    ? undefined
    : {
        transform: CSS.Transform.toString(transform),
        transition,
        opacity: isDragging ? 0.5 : 1,
      };
  const sharedShotDisplayProps = {
    shot,
    onSelectShot,
    onDuplicateShot,
    currentProjectId,
    shouldLoadImages,
    shotIndex,
    projectAspectRatio,
    dataTour,
    finalVideo,
  } as const;

  return (
    <div
      ref={setNodeRef}
      style={style}
      onDragEnter={handleDragEnter}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={cn(
        'transition-all duration-200 relative self-start',
        isDropTarget && 'ring-2 ring-primary ring-offset-2 ring-offset-background scale-[1.02]'
      )}
    >
      <VideoShotDisplay
        {...sharedShotDisplayProps}
        isHighlighted={isHighlighted || isDropTarget}
        pendingUploads={pendingSkeletonCount}
        dropLoadingState={withPositionDropState}
      />

      {(isDropTarget || withoutPositionDropState !== 'idle') && (
        <div
          ref={withoutPositionZoneRef}
          onDragEnter={handleWithoutPositionDragEnter}
          onDragOver={handleWithoutPositionDragOver}
          onDragLeave={handleWithoutPositionDragLeave}
          onDrop={handleWithoutPositionDrop}
          className={cn(
            'absolute bottom-2 left-2 px-2 py-1 rounded text-xs font-medium transition-all duration-150 z-10 flex items-center gap-1.5',
            withoutPositionDropState === 'idle' && 'bg-muted/90 text-muted-foreground border border-border/50',
            withoutPositionDropState === 'idle' && isOverWithoutPositionZone && 'bg-primary text-primary-foreground border-primary scale-105',
            withoutPositionDropState === 'loading' && 'bg-primary/90 text-primary-foreground border border-primary',
            withoutPositionDropState === 'success' && 'bg-green-600 text-white border border-green-600'
          )}
        >
          {withoutPositionDropState === 'loading' && (
            <>
              <Loader2 className="h-3 w-3 animate-spin" />
              Adding...
            </>
          )}
          {withoutPositionDropState === 'success' && (
            <>
              <Check className="h-3 w-3" />
              Added
            </>
          )}
          {withoutPositionDropState === 'idle' && 'Without Position'}
        </div>
      )}
    </div>
  );
};

/**
 * Shared utilities for drag-and-drop operations involving generations (images/videos)
 *
 * Used by:
 * - MediaGalleryItem (drag source)
 * - ShotGroup, SortableShotItem, ShotListDisplay (drop targets)
 * - Timeline components (drop targets)
 * - BatchDropZone (drop target)
 */

import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';

// MIME type for generation drag data
const GENERATION_MIME_TYPE = 'application/x-generation';
const GENERATION_TEXT_PREFIX = '__reigh_generation__:';
export const GENERATION_MULTI_DRAG_TYPE = 'application/x-generation-multi';
const GENERATION_MULTI_TEXT_PREFIX = '__reigh_generation_multi__:';

// Droppable ID for creating a new shot from a dropped generation
export const NEW_GROUP_DROPPABLE_ID = 'new-shot-group-dropzone';

/**
 * Cross-browser safe check for whether a DataTransfer contains a type.
 */
function hasDataTransferType(dataTransfer: DataTransfer, type: string): boolean {
  const types = dataTransfer?.types;
  if (!types) return false;

  if (typeof types.includes === 'function') {
    try {
      return !!types.includes(type);
    } catch {
      // ignore
    }
  }

  const length = typeof types.length === 'number' ? types.length : 0;
  for (let i = 0; i < length; i += 1) {
    if (types[i] === type) return true;
  }

  return false;
}

/**
 * Data structure for dragging generations between components
 */
export interface GenerationDropData {
  generationId: string;
  variantId?: string;
  variantType?: string;
  imageUrl: string;
  thumbUrl?: string;
  metadata?: Record<string, unknown>;
}

/**
 * Type of drag operation
 */
export type DragType = 'generation' | 'generation-multi' | 'file' | 'none';

function isMultiGenerationDrag(e: React.DragEvent): boolean {
  if (hasDataTransferType(e.dataTransfer, GENERATION_MULTI_DRAG_TYPE)) {
    return true;
  }

  if (!hasDataTransferType(e.dataTransfer, 'text/plain')) {
    return false;
  }

  const textPayload = e.dataTransfer.getData('text/plain');
  return parseMultiGenerationDropData(textPayload) !== null;
}

/**
 * Check if the drag event contains generation data.
 * @internal Used by getDragType.
 */
function isGenerationDrag(e: React.DragEvent): boolean {
  if (hasDataTransferType(e.dataTransfer, GENERATION_MIME_TYPE)) {
    return true;
  }

  if (!hasDataTransferType(e.dataTransfer, 'text/plain')) {
    return false;
  }

  const textPayload = e.dataTransfer.getData('text/plain');
  return parseGenerationDropData(textPayload) !== null;
}

/**
 * Check if the drag event contains files
 */
export function isFileDrag(e: React.DragEvent): boolean {
  return hasDataTransferType(e.dataTransfer, 'Files');
}

/**
 * Determine the type of drag operation
 */
export function getDragType(e: React.DragEvent): DragType {
  if (isMultiGenerationDrag(e)) return 'generation-multi';
  if (isGenerationDrag(e)) return 'generation';
  if (isFileDrag(e)) return 'file';
  return 'none';
}

/**
 * Set generation drag data on the dataTransfer object
 * Call this in onDragStart
 */
export function setGenerationDragData(e: React.DragEvent, data: GenerationDropData): void {
  const serialized = JSON.stringify(data);
  e.dataTransfer.effectAllowed = 'copy';
  e.dataTransfer.setData(GENERATION_MIME_TYPE, serialized);
  // Fallback: some browsers/targets are inconsistent about exposing custom MIME types during dragover.
  try {
    e.dataTransfer.setData('text/plain', `${GENERATION_TEXT_PREFIX}${serialized}`);
  } catch {
    // ignore
  }
}

export function setMultiGenerationDragData(
  e: React.DragEvent,
  items: GenerationDropData[],
): void {
  const serialized = JSON.stringify(items);
  e.dataTransfer.effectAllowed = 'copy';
  e.dataTransfer.setData(GENERATION_MULTI_DRAG_TYPE, serialized);
  try {
    e.dataTransfer.setData('text/plain', `${GENERATION_MULTI_TEXT_PREFIX}${serialized}`);
  } catch {
    // ignore
  }
}

function parseGenerationDropData(dataString: string): GenerationDropData | null {
  if (!dataString) {
    return null;
  }

  let data: GenerationDropData;
  try {
    const normalized = dataString.startsWith(GENERATION_TEXT_PREFIX)
      ? dataString.slice(GENERATION_TEXT_PREFIX.length)
      : dataString;
    data = JSON.parse(normalized) as GenerationDropData;
  } catch {
    return null;
  }

  if (!data.generationId || !data.imageUrl) {
    return null;
  }

  return data;
}

function parseMultiGenerationDropData(dataString: string): GenerationDropData[] | null {
  if (!dataString) {
    return null;
  }

  let data: unknown;
  try {
    const normalized = dataString.startsWith(GENERATION_MULTI_TEXT_PREFIX)
      ? dataString.slice(GENERATION_MULTI_TEXT_PREFIX.length)
      : dataString;
    data = JSON.parse(normalized);
  } catch {
    return null;
  }

  if (!Array.isArray(data) || data.length === 0) {
    return null;
  }

  const items = data
    .map((item) => parseGenerationDropData(JSON.stringify(item)))
    .filter((item): item is GenerationDropData => item !== null);

  return items.length === data.length ? items : null;
}

/**
 * Get and parse generation drag data from the dataTransfer object
 * Call this in onDrop
 * Returns null if no valid data found
 */
export function getGenerationDropData(e: React.DragEvent): GenerationDropData | null {
  try {
    const dataString =
      e.dataTransfer.getData(GENERATION_MIME_TYPE) ||
      e.dataTransfer.getData('text/plain');
    return parseGenerationDropData(dataString);
  } catch (error) {
    normalizeAndPresentError(error, { context: 'DragDrop', showToast: false });
    return null;
  }
}

export function getMultiGenerationDropData(e: React.DragEvent): GenerationDropData[] | null {
  try {
    const dataString =
      e.dataTransfer.getData(GENERATION_MULTI_DRAG_TYPE) ||
      e.dataTransfer.getData('text/plain');
    return parseMultiGenerationDropData(dataString);
  } catch (error) {
    normalizeAndPresentError(error, { context: 'DragDrop', showToast: false });
    return null;
  }
}

/**
 * Check if the drag event is a valid drop target (generation or file)
 */
export function isValidDropTarget(e: React.DragEvent): boolean {
  return isMultiGenerationDrag(e) || isGenerationDrag(e) || isFileDrag(e);
}

/**
 * Create a visual drag preview element
 * Returns a cleanup function to remove the element
 */
export function createDragPreview(
  e: React.DragEvent, 
  options?: { 
    size?: number; 
    borderColor?: string;
    badgeText?: string;
  }
): (() => void) | null {
  const { size = 80, borderColor = '#fff', badgeText } = options || {};

  if (!e.dataTransfer.setDragImage || !(e.currentTarget instanceof HTMLElement)) {
    return null;
  }

  const preview = document.createElement('div');
  preview.style.position = 'absolute';
  preview.style.top = '-1000px';
  preview.style.width = `${size}px`;
  preview.style.height = `${size}px`;
  preview.style.opacity = '0.7';
  preview.style.borderRadius = '8px';
  preview.style.overflow = 'hidden';
  preview.style.border = `2px solid ${borderColor}`;
  preview.style.boxShadow = '0 4px 6px hsl(0 0% 0% / 0.3)';

  const imgElement = e.currentTarget.querySelector('img');
  if (imgElement) {
    const imgClone = imgElement.cloneNode(true) as HTMLImageElement;
    imgClone.style.width = '100%';
    imgClone.style.height = '100%';
    imgClone.style.objectFit = 'cover';
    preview.appendChild(imgClone);
  }

import React from 'react';
import {
  DndContext,
  closestCenter,
} from '@dnd-kit/core';
import {
  SortableContext,
  rectSortingStrategy,
} from '@dnd-kit/sortable';
import { Shot } from '@/domains/generation/types';
import { SortableShotItem, type DropOptions } from './SortableShotItem';
import { type GenerationDropData } from '@/shared/lib/dnd/dragDrop';
import { useShotFinalVideos } from '../../hooks/video/useShotFinalVideos';
import {
  NewShotDropZoneCard,
  PendingSkeletonShotCard,
  ShotListEmptyState,
  ShotListErrorState,
  ShotListLoadingState,
} from './components/ShotListDisplayStates';
import { useShotListDisplayController } from './hooks/useShotListDisplayController';

interface ShotListDisplayProps {
  projectId: string;
  onSelectShot: (shot: Shot) => void;
  onCreateNewShot?: () => void;
  shots?: Shot[];
  sortMode?: 'ordered' | 'newest' | 'oldest';
  onSortModeChange?: (mode: 'ordered' | 'newest' | 'oldest') => void;
  highlightedShotId?: string | null;
  onGenerationDropOnShot?: (shotId: string, data: GenerationDropData, options?: DropOptions) => Promise<void>;
  onGenerationDropForNewShot?: (data: GenerationDropData) => Promise<void>;
  onFilesDropForNewShot?: (files: File[]) => Promise<void>;
  onFilesDropOnShot?: (shotId: string, files: File[], options?: DropOptions) => Promise<void>;
  onSkeletonSetupReady?: (setup: (imageCount: number) => void, clear: () => void) => void;
}

export const ShotListDisplay: React.FC<ShotListDisplayProps> = ({
  projectId,
  onSelectShot,
  onCreateNewShot,
  shots: propShots,
  sortMode = 'ordered',
  onSortModeChange,
  highlightedShotId,
  onGenerationDropOnShot,
  onGenerationDropForNewShot,
  onFilesDropForNewShot,
  onFilesDropOnShot,
  onSkeletonSetupReady,
}) => {
  const {
    shotsLoading,
    shotsError,
    shots,
    currentProject,
    effectiveProjectId,
    sensors,
    handleDragStart,
    handleDragEnd,
    sortableItems,
    pendingNewShot,
    isDragDisabled,
  } = useShotListDisplayController({
    projectId,
    shots: propShots,
    sortMode,
    onGenerationDropForNewShot,
    onFilesDropForNewShot,
    onSkeletonSetupReady,
  });

  const { finalVideoMap } = useShotFinalVideos(effectiveProjectId);

  if (shotsLoading || shots === undefined) {
    return <ShotListLoadingState />;
  }

  if (shotsError) {
    return <ShotListErrorState errorMessage={shotsError.message} onCreateNewShot={onCreateNewShot} />;
  }

  if (!shots || shots.length === 0) {
    return <ShotListEmptyState onCreateNewShot={onCreateNewShot} />;
  }

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCenter}
      onDragStart={handleDragStart}
      onDragEnd={handleDragEnd}
    >
      <SortableContext
        items={sortableItems}
        strategy={rectSortingStrategy}
      >
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-x-6 md:gap-y-5 pb-6 md:pb-8 px-4 pt-4 pb-2">
          {(onGenerationDropForNewShot || onFilesDropForNewShot) && (
            <NewShotDropZoneCard
              isNewShotProcessing={pendingNewShot.isNewShotProcessing}
              isNewShotDropTarget={pendingNewShot.isNewShotDropTarget}
              newShotDropType={pendingNewShot.newShotDropType}
              onDragEnter={pendingNewShot.handleNewShotDragEnter}
              onDragOver={pendingNewShot.handleNewShotDragOver}
              onDragLeave={pendingNewShot.handleNewShotDragLeave}
              onDrop={pendingNewShot.handleNewShotDrop}
              onClick={pendingNewShot.isNewShotProcessing ? undefined : onCreateNewShot}
            />
          )}

          {pendingNewShot.pendingSkeletonShot && (
            <PendingSkeletonShotCard pendingSkeletonShot={pendingNewShot.pendingSkeletonShot} />
          )}

          {shots.map((shot, index) => {
            return (
              <SortableShotItem
                key={shot.id}
                shot={shot}
                onSelectShot={() => onSelectShot(shot)}
                onDuplicateShot={() => onSortModeChange?.('newest')}
                currentProjectId={effectiveProjectId}
                isDragDisabled={isDragDisabled}
                disabledReason={sortMode !== 'ordered' ? 'Only available in ordered mode' : undefined}
                shouldLoadImages={true}
                shotIndex={index}
                projectAspectRatio={currentProject?.aspectRatio}
                isHighlighted={highlightedShotId === shot.id}
                onGenerationDrop={onGenerationDropOnShot}
                onFilesDrop={onFilesDropOnShot}
                initialPendingUploads={shot.id === pendingNewShot.newlyCreatedShotId ? pendingNewShot.newlyCreatedShotExpectedImages : 0}
                initialPendingBaselineNonVideoCount={shot.id === pendingNewShot.newlyCreatedShotId ? pendingNewShot.newlyCreatedShotBaselineNonVideoCount : undefined}
                onInitialPendingUploadsConsumed={shot.id === pendingNewShot.newlyCreatedShotId ? pendingNewShot.clearNewlyCreatedShot : undefined}
                dataTour={index === 0 ? 'first-shot' : undefined}
                finalVideo={finalVideoMap.get(shot.id)}
              />
            );
          })}
        </div>
      </SortableContext>
    </DndContext>
  );
};

import { describe, it, expect } from 'vitest';

// Mock errorHandler to avoid pulling in toast/Supabase dependencies
import {
  getDragType,
  setGenerationDragData,
  setMultiGenerationDragData,
  getGenerationDropData,
  getMultiGenerationDropData,
  isValidDropTarget,
  isFileDrag,
  NEW_GROUP_DROPPABLE_ID,
  GENERATION_MULTI_DRAG_TYPE,
} from '../dnd/dragDrop';
import type { GenerationDropData } from '../dnd/dragDrop';

/**
 * Create a minimal mock of React.DragEvent for testing
 */
function createMockDragEvent(overrides: {
  types?: string[];
  data?: Record<string, string>;
} = {}): React.DragEvent {
  const storedData: Record<string, string> = overrides.data ?? {};
  const types = overrides.types ?? Object.keys(storedData);

  return {
    dataTransfer: {
      types,
      effectAllowed: 'none',
      setData: (type: string, value: string) => {
        storedData[type] = value;
      },
      getData: (type: string) => storedData[type] ?? '',
    },
  } as unknown as React.DragEvent;
}

describe('getDragType', () => {
  it('returns "generation" for generation MIME type', () => {
    const event = createMockDragEvent({ types: ['application/x-generation'] });
    expect(getDragType(event)).toBe('generation');
  });

  it('returns "file" for Files type', () => {
    const event = createMockDragEvent({ types: ['Files'] });
    expect(getDragType(event)).toBe('file');
  });

  it('returns "generation-multi" for multi-generation MIME type', () => {
    const event = createMockDragEvent({ types: [GENERATION_MULTI_DRAG_TYPE] });
    expect(getDragType(event)).toBe('generation-multi');
  });

  it('returns "none" for plain text without generation payload', () => {
    const event = createMockDragEvent({
      types: ['text/plain'],
      data: { 'text/plain': 'hello world' },
    });
    expect(getDragType(event)).toBe('none');
  });

  it('returns "none" for empty types', () => {
    const event = createMockDragEvent({ types: [] });
    expect(getDragType(event)).toBe('none');
  });

  it('prefers generation over file when both present', () => {
    const event = createMockDragEvent({ types: ['application/x-generation', 'Files'] });
    expect(getDragType(event)).toBe('generation');
  });
});

describe('isFileDrag', () => {
  it('returns true when Files type present', () => {
    const event = createMockDragEvent({ types: ['Files'] });
    expect(isFileDrag(event)).toBe(true);
  });

  it('returns false when no Files type', () => {
    const event = createMockDragEvent({ types: ['text/plain'] });
    expect(isFileDrag(event)).toBe(false);
  });
});

describe('setGenerationDragData / getGenerationDropData round-trip', () => {
  it('round-trips generation data through set and get', () => {
    const data: GenerationDropData = {
      generationId: 'gen-123',
      imageUrl: 'https://example.com/img.png',
      thumbUrl: 'https://example.com/thumb.png',
      metadata: { prompt: 'a cat' },
    };

    const storedData: Record<string, string> = {};
    const setEvent = createMockDragEvent({ data: storedData });
    setGenerationDragData(setEvent, data);

    // Verify data was stored
    expect(storedData['application/x-generation']).toBeTruthy();
    expect(storedData['text/plain']).toContain('__reigh_generation__:');

    const getEvent = createMockDragEvent({
      types: ['application/x-generation'],
      data: storedData,
    });
    const result = getGenerationDropData(getEvent);

    expect(result).toEqual(data);
  });

  it('returns null when no data in dataTransfer', () => {
    const event = createMockDragEvent({ data: {} });
    expect(getGenerationDropData(event)).toBeNull();
  });

  it('returns null for malformed JSON', () => {
    const event = createMockDragEvent({
      data: { 'application/x-generation': 'not-json' },
    });
    expect(getGenerationDropData(event)).toBeNull();
  });

  it('returns null when required fields missing', () => {
    const event = createMockDragEvent({
      data: { 'application/x-generation': JSON.stringify({ generationId: 'gen-1' }) }, // missing imageUrl
    });
    expect(getGenerationDropData(event)).toBeNull();
  });

  it('falls back to text/plain data', () => {
    const data: GenerationDropData = {
      generationId: 'gen-456',
      imageUrl: 'https://example.com/img.png',
    };

    const event = createMockDragEvent({
      data: { 'text/plain': `__reigh_generation__:${JSON.stringify(data)}` },
    });
    const result = getGenerationDropData(event);
    expect(result).toEqual(data);
  });

  it('detects generation drags from prefixed text/plain payloads', () => {
    const event = createMockDragEvent({
      types: ['text/plain'],
      data: {
        'text/plain': '__reigh_generation__:{"generationId":"gen-789","imageUrl":"https://example.com/video.mp4"}',
      },
    });

    expect(getDragType(event)).toBe('generation');
    expect(isValidDropTarget(event)).toBe(true);
  });
});

describe('setMultiGenerationDragData / getMultiGenerationDropData round-trip', () => {
  it('round-trips multi-generation data through set and get', () => {
    const data: GenerationDropData[] = [
      {
        generationId: 'gen-123',
        imageUrl: 'https://example.com/img-1.png',
      },
      {
        generationId: 'gen-456',
        imageUrl: 'https://example.com/img-2.png',
        thumbUrl: 'https://example.com/thumb-2.png',
      },
    ];

    const storedData: Record<string, string> = {};
    const setEvent = createMockDragEvent({ data: storedData });
    setMultiGenerationDragData(setEvent, data);

    expect(storedData[GENERATION_MULTI_DRAG_TYPE]).toBeTruthy();
    expect(storedData['text/plain']).toContain('__reigh_generation_multi__:');

    const getEvent = createMockDragEvent({
      types: [GENERATION_MULTI_DRAG_TYPE],
      data: storedData,
    });

    expect(getMultiGenerationDropData(getEvent)).toEqual(data);
    expect(getDragType(getEvent)).toBe('generation-multi');
  });

  it('returns null for invalid multi-generation payloads', () => {
    const malformedEvent = createMockDragEvent({
      data: { [GENERATION_MULTI_DRAG_TYPE]: 'not-json' },
    });
    expect(getMultiGenerationDropData(malformedEvent)).toBeNull();

    const invalidShapeEvent = createMockDragEvent({
      data: {
        [GENERATION_MULTI_DRAG_TYPE]: JSON.stringify([{ generationId: 'gen-1' }]),
      },
    });
    expect(getMultiGenerationDropData(invalidShapeEvent)).toBeNull();
  });
});

describe('isValidDropTarget', () => {
  it('returns true for generation drag', () => {
    const event = createMockDragEvent({ types: ['application/x-generation'] });
    expect(isValidDropTarget(event)).toBe(true);
  });

  it('returns true for multi-generation drag', () => {
    const event = createMockDragEvent({ types: [GENERATION_MULTI_DRAG_TYPE] });
    expect(isValidDropTarget(event)).toBe(true);
  });

  it('returns true for file drag', () => {
    const event = createMockDragEvent({ types: ['Files'] });
    expect(isValidDropTarget(event)).toBe(true);
  });

  it('returns false for other drag types', () => {
    const event = createMockDragEvent({
      types: ['text/plain'],
      data: { 'text/plain': 'hello world' },
    });
    expect(isValidDropTarget(event)).toBe(false);
  });
});

describe('constants', () => {
  it('exports NEW_GROUP_DROPPABLE_ID', () => {
    expect(NEW_GROUP_DROPPABLE_ID).toBe('new-shot-group-dropzone');
  });
});

import React, { useMemo, useState } from 'react';
