          selectedClipId: options?.selectedClipId,
          selectedTrackId: options?.selectedTrackId,
          transactionId: options?.transactionId,
          semantic: options?.semantic,
        },
      );
      return;
    }

    if (mutation.type === 'rows') {
      const nextMeta: Record<string, ClipMeta> = { ...current.meta };

      if (mutation.metaUpdates) {
        for (const [clipId, patch] of Object.entries(mutation.metaUpdates)) {
          nextMeta[clipId] = nextMeta[clipId]
            ? { ...nextMeta[clipId], ...patch }
            : (patch as ClipMeta);
        }
      }

      if (mutation.metaDeletes) {
        for (const clipId of mutation.metaDeletes) {
          delete nextMeta[clipId];
        }
      }

      const baseNextData = materializeData(
        current,
        mutation.rows,
        nextMeta,
        mutation.clipOrderOverride ?? buildTrackClipOrder(current.tracks, current.clipOrder, mutation.metaDeletes),
      );
      const nextData = mutation.pinnedShotGroupsOverride === undefined
        ? baseNextData
        : preserveUploadingClips(
            { ...current, rows: mutation.rows, meta: nextMeta } as TimelineData,
            buildDataFromCurrentRegistry(
              withPinnedShotGroups(baseNextData.config, mutation.pinnedShotGroupsOverride),
              current,
            ),
          );

      commitData(
        nextData,
        {
          save: options?.save,
          transactionId: options?.transactionId,
          semantic: options?.semantic,
        },
      );
      return;
    }

    commitData(
      preserveUploadingClips(
        current,
        buildDataFromCurrentRegistry(
          serializeForDisk(
            mutation.resolvedConfig,
            current.config.customEffects,
            current.config.pinnedShotGroups,
          ),
          current,
        ),
      ),
      {
        save: options?.save,
        selectedClipId: options?.selectedClipId,
        selectedTrackId: options?.selectedTrackId,
        transactionId: options?.transactionId,
        semantic: options?.semantic,
      },
    );
  }, [commitData, materializeData, withPinnedShotGroups]);

  const patchRegistry = useCallback((assetId: string, entry: AssetRegistryEntry, src?: string) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const nextRegistry = {
      ...current.registry,
      assets: {
        ...current.registry.assets,
        [assetId]: entry,
      },
    };
    const nextResolvedRegistry = {
      ...current.resolvedConfig.registry,
      [assetId]: {
        ...entry,
        src: src ?? current.resolvedConfig.registry[assetId]?.src ?? entry.file,
      },
    };
    const nextConfig = {
      ...current.config,
      customEffects: current.config.customEffects
        ? { ...current.config.customEffects }
        : undefined,
    };

// @vitest-environment jsdom
import { renderHook } from '@testing-library/react';
import { describe, expect, it } from 'vitest';
import type { Shot } from '@/domains/generation/types';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { AssetRegistry } from '@/tools/video-editor/types';
import type { TimelineAction, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import { getShotColor, useShotGroups } from './useShotGroups';

function buildAction(id: string, start: number, end: number): TimelineAction {
  return { id, start, end, effectId: `effect-${id}` };
}

function buildShot(id: string, name: string, generationIds: string[]): Shot {
  return {
    id,
    name,
    images: generationIds.map((generationId, index) => ({
      id: `${id}-image-${index}`,
      generation_id: generationId,
    })),
  } as Shot;
}

function buildMeta(trackId: string, assetMap: Record<string, string | undefined>): Record<string, ClipMeta> {
  return Object.fromEntries(
    Object.entries(assetMap).map(([clipId, asset]) => [clipId, { track: trackId, asset, clipType: 'media' }]),
  );
}

function buildRegistry(generationMap: Record<string, string | undefined>): AssetRegistry {
  return {
    assets: Object.fromEntries(
      Object.entries(generationMap).map(([assetId, generationId]) => [assetId, { file: `${assetId}.png`, generationId }]),
    ),
  };
}

describe('useShotGroups', () => {
  it('returns one group for adjacent clips in the same shot order on one track', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-1', 0, 1), buildAction('clip-2', 1, 2), buildAction('clip-3', 2, 3)] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      buildMeta('V1', { 'clip-1': 'asset-1', 'clip-2': 'asset-2', 'clip-3': 'asset-3' }),
      buildRegistry({ 'asset-1': 'gen-1', 'asset-2': 'gen-2', 'asset-3': 'gen-3' }),
      [buildShot('shot-1', 'Shot 1', ['gen-1', 'gen-2', 'gen-3'])],
    ));

    expect(result.current).toEqual([{
      shotId: 'shot-1',
      shotName: 'Shot 1',
      rowId: 'V1',
      rowIndex: 0,
      clipIds: ['clip-1', 'clip-2', 'clip-3'],
      color: getShotColor('shot-1'),
    }]);
  });

  it('does not group clips when the gap exceeds the threshold', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-1', 0, 1), buildAction('clip-2', 1.6, 2.6)] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      buildMeta('V1', { 'clip-1': 'asset-1', 'clip-2': 'asset-2' }),
      buildRegistry({ 'asset-1': 'gen-1', 'asset-2': 'gen-2' }),
      [buildShot('shot-1', 'Shot 1', ['gen-1', 'gen-2'])],
    ));

    expect(result.current).toEqual([]);
  });

  it('does not group clips when their order disagrees with the shot image order', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-2', 0, 1), buildAction('clip-1', 1, 2)] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      buildMeta('V1', { 'clip-1': 'asset-1', 'clip-2': 'asset-2' }),
      buildRegistry({ 'asset-1': 'gen-1', 'asset-2': 'gen-2' }),
      [buildShot('shot-1', 'Shot 1', ['gen-1', 'gen-2'])],
    ));

    expect(result.current).toEqual([]);
  });

  it('returns separate groups for different shots on the same track', () => {
    const rows: TimelineRow[] = [{
      id: 'V1',
      actions: [buildAction('clip-1', 0, 1), buildAction('clip-2', 1, 2), buildAction('clip-3', 3, 4), buildAction('clip-4', 4, 5)],
    }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      buildMeta('V1', { 'clip-1': 'asset-1', 'clip-2': 'asset-2', 'clip-3': 'asset-3', 'clip-4': 'asset-4' }),
      buildRegistry({ 'asset-1': 'gen-1', 'asset-2': 'gen-2', 'asset-3': 'gen-3', 'asset-4': 'gen-4' }),
      [buildShot('shot-a', 'Shot A', ['gen-1', 'gen-2']), buildShot('shot-b', 'Shot B', ['gen-3', 'gen-4'])],
    ));

    expect(result.current.map((group) => ({ shotId: group.shotId, clipIds: group.clipIds }))).toEqual([
      { shotId: 'shot-a', clipIds: ['clip-1', 'clip-2'] },
      { shotId: 'shot-b', clipIds: ['clip-3', 'clip-4'] },
    ]);
  });

  it('does not create groups for a single matching clip', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-1', 0, 1)] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      buildMeta('V1', { 'clip-1': 'asset-1' }),
      buildRegistry({ 'asset-1': 'gen-1' }),
      [buildShot('shot-1', 'Shot 1', ['gen-1'])],
    ));

    expect(result.current).toEqual([]);
  });

  it('does not group clips across tracks even if they belong to the same shot', () => {
    const rows: TimelineRow[] = [
      { id: 'V1', actions: [buildAction('clip-1', 0, 1)] },
      { id: 'V2', actions: [buildAction('clip-2', 1, 2)] },
    ];
    const meta = {
      ...buildMeta('V1', { 'clip-1': 'asset-1' }),
      ...buildMeta('V2', { 'clip-2': 'asset-2' }),
    };
    const { result } = renderHook(() => useShotGroups(
      rows,
      meta,
      buildRegistry({ 'asset-1': 'gen-1', 'asset-2': 'gen-2' }),
      [buildShot('shot-1', 'Shot 1', ['gen-1', 'gen-2'])],
    ));

    expect(result.current).toEqual([]);
  });

  it('returns deterministic colors and different colors for distinct sample shot ids', () => {
    expect(getShotColor('shot-a')).toBe(getShotColor('shot-a'));
    expect(new Set(['shot-a', 'shot-b', 'shot-c'].map((shotId) => getShotColor(shotId))).size).toBe(3);
  });

  it('ignores clips without generation ids instead of throwing', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-1', 0, 1), buildAction('clip-2', 1, 2), buildAction('clip-3', 2, 3)] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      buildMeta('V1', { 'clip-1': 'asset-1', 'clip-2': 'asset-2', 'clip-3': 'asset-3' }),
      buildRegistry({ 'asset-1': 'gen-1', 'asset-2': undefined, 'asset-3': 'gen-3' }),
      [buildShot('shot-1', 'Shot 1', ['gen-1', 'gen-2', 'gen-3'])],
    ));

    expect(result.current).toEqual([]);
  });
});

import { useCallback } from 'react';
import type { Dispatch, MutableRefObject, SetStateAction } from 'react';
import { getGenerationDropData } from '@/shared/lib/dnd/dragDrop';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { uploadImageToStorage } from '@/shared/lib/media/imageUploader';
import { generateClientThumbnail, uploadImageWithThumbnail } from '@/shared/media/clientThumbnailGenerator';
import { createExternalUploadGeneration } from '@/integrations/supabase/repositories/generationMutationsRepository';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { getCompatibleTrackId, updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getTrackIndex } from '@/tools/video-editor/lib/editor-utils';
import {
  getNextClipId,
  inferTrackType,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type {
  TimelineApplyEdit,
  TimelineInvalidateAssetRegistry,
  TimelinePatchRegistry,
  TimelineRegisterAsset,
  TimelineUploadAsset,
} from '@/tools/video-editor/hooks/timeline-state-types';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';
import type { AssetRegistryEntry, ClipType } from '@/tools/video-editor/types';

export interface UseAssetManagementArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  selectedTrackId: string | null;
  selectedProjectId: string | null;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  applyEdit: TimelineApplyEdit;
  patchRegistry: TimelinePatchRegistry;
  registerAsset: TimelineRegisterAsset;
  uploadAsset: TimelineUploadAsset;
  invalidateAssetRegistry: TimelineInvalidateAssetRegistry;
  resolveAssetUrl: (file: string) => Promise<string>;
}

export interface UseAssetManagementResult {
  registerGenerationAsset: (data: ReturnType<typeof getGenerationDropData>) => string | null;
  uploadImageGeneration: (file: File) => Promise<{
    generationId: string;
    variantType: 'image';
    imageUrl: string;
    thumbUrl: string;
    metadata: {
      content_type: string;
      original_filename: string;
    };
  }>;
  handleAssetDrop: (assetKey: string, trackId: string | undefined, time: number, forceNewTrack?: boolean, insertAtTop?: boolean) => void;
}

export function useAssetManagement({
  dataRef,
  selectedTrackId,
  selectedProjectId,
  setSelectedClipId,
  setSelectedTrackId,
  applyEdit,
  patchRegistry,
  registerAsset,
}: UseAssetManagementArgs): UseAssetManagementResult {
  const registerGenerationAsset = useCallback((generationData: ReturnType<typeof getGenerationDropData>) => {
    if (!generationData) {
      return null;
    }

    const mimeType = (() => {
      const metadataContentType = typeof generationData.metadata?.content_type === 'string'
        ? generationData.metadata.content_type
        : null;
      if (metadataContentType?.includes('/')) {
        return metadataContentType;
      }
      if (metadataContentType === 'video' || generationData.variantType === 'video' || /\.(mp4|mov|webm|m4v)$/i.test(generationData.imageUrl)) {
        return 'video/mp4';
      }
      if (metadataContentType === 'audio' || /\.(mp3|wav|aac|m4a)$/i.test(generationData.imageUrl)) {
        return 'audio/mpeg';
      }
      return 'image/png';
    })();

    const assetId = generateUUID();
    const entry: AssetRegistryEntry = {
      file: generationData.imageUrl,
      type: mimeType,
      generationId: generationData.generationId,
      variantId: generationData.variantId,
    };

    patchRegistry(assetId, entry, generationData.imageUrl);
    void registerAsset(assetId, entry).catch((error) => {
      console.error('[video-editor] Failed to persist generation asset:', error);
    });

    return assetId;
  }, [patchRegistry, registerAsset]);

  const uploadImageGeneration = useCallback(async (file: File) => {
    if (!selectedProjectId) {
      throw new Error('External image drop requires a selected project');
    }

    let imageUrl = '';
    let thumbnailUrl = '';

    try {
      const thumbnailResult = await generateClientThumbnail(file, 300, 0.8);
      const uploadResult = await uploadImageWithThumbnail(file, thumbnailResult.thumbnailBlob);
      imageUrl = uploadResult.imageUrl;
      thumbnailUrl = uploadResult.thumbnailUrl;
    } catch (error) {
      normalizeAndPresentError(error, { context: `video-editor:external-drop:${file.name}`, showToast: false });
      imageUrl = await uploadImageToStorage(file, 3);
      thumbnailUrl = imageUrl;
    }

    const generation = await createExternalUploadGeneration({
      imageUrl,
      thumbnailUrl,
      fileType: 'image',
      projectId: selectedProjectId,
      generationParams: {
        prompt: `Uploaded ${file.name}`,
        extra: {
          source: 'external_upload',
          original_filename: file.name,
          file_type: file.type || 'image',
          file_size: file.size,
        },
      },
    });

    return {
      generationId: generation.id,
      variantType: 'image' as const,
      imageUrl,
      thumbUrl: thumbnailUrl,
      metadata: {
        content_type: file.type || 'image',
        original_filename: file.name,
      },
    };
  }, [selectedProjectId]);

  const handleAssetDrop = useCallback((assetKey: string, trackId: string | undefined, time: number, forceNewTrack = false, insertAtTop = false) => {
    let current = dataRef.current;
    if (!current) {
      return;
    }

    const assetEntry = current.registry.assets[assetKey];
    const assetKind = inferTrackType(assetEntry?.file ?? assetKey);
    let resolvedTrackId = forceNewTrack
      ? null
      : getCompatibleTrackId(current.tracks, trackId, assetKind, selectedTrackId);

    // If no compatible track exists (or forced new track), create one immutably
    if (!resolvedTrackId) {
      const latest = dataRef.current;
      if (!latest) {
        return;
      }

      const existingTrackId = forceNewTrack
        ? null
        : getCompatibleTrackId(latest.tracks, trackId, assetKind, selectedTrackId);
      if (existingTrackId) {
        current = latest;
        resolvedTrackId = existingTrackId;
      } else {
        const prefix = assetKind === 'audio' ? 'A' : 'V';
        const nextNumber = getTrackIndex(latest.tracks, prefix) + 1;
        resolvedTrackId = `${prefix}${nextNumber}`;
        const newTrack = {
          id: resolvedTrackId,
          kind: assetKind,
          label: `${prefix}${nextNumber}`,
        };
        current = {
          ...latest,
          tracks: insertAtTop ? [newTrack, ...latest.tracks] : [...latest.tracks, newTrack],
          rows: insertAtTop ? [{ id: resolvedTrackId, actions: [] }, ...latest.rows] : [...latest.rows, { id: resolvedTrackId, actions: [] }],
        };
        dataRef.current = current;
      }
    }

    const track = current.tracks.find((candidate) => candidate.id === resolvedTrackId);
    if (!track) {
      return;
    }

    const clipId = getNextClipId(current.meta);
    const isImage = assetEntry?.type?.startsWith('image');
    const isVideo = assetEntry?.type?.startsWith('video') || (!isImage && assetKind === 'visual' && assetEntry?.duration);
    const isManual = track.fit === 'manual';
    const clipType: ClipType = isImage ? 'hold' : 'media';
    // Use actual asset duration for videos/audio instead of capping at 5s
    const baseDuration = isVideo
      ? (assetEntry?.duration ?? 5)
      : isImage
        ? 5
        : Math.max(1, assetEntry?.duration ?? 5);

    let clipMeta: ClipMeta;
    let duration: number;

    if (track.kind === 'audio') {
      duration = assetEntry?.duration ?? 10;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType: 'media',
        from: 0,
        to: duration,
        speed: 1,
        volume: 1,
      };
    } else if (isImage) {
      duration = 5;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType,
        hold: duration,
        opacity: 1,
        x: isManual ? 100 : undefined,
        y: isManual ? 100 : undefined,
        width: isManual ? 320 : undefined,
        height: isManual ? 240 : undefined,
      };
    } else {
      duration = baseDuration;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType,
        from: 0,
        to: duration,
        speed: 1,
        volume: 1,
        opacity: 1,
        x: isManual ? 100 : undefined,
        y: isManual ? 100 : undefined,
        width: isManual ? 320 : undefined,
        height: isManual ? 240 : undefined,
      };
    }

    const action: TimelineAction = {
      id: clipId,
      start: time,
      end: time + duration,
      effectId: `effect-${clipId}`,
    };

    const nextRows = current.rows.map((row) => (row.id === resolvedTrackId ? { ...row, actions: [...row.actions, action] } : row));
    const nextClipOrder = updateClipOrder(current.clipOrder, resolvedTrackId, (ids) => [...ids, clipId]);
    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: { [clipId]: clipMeta },
      clipOrderOverride: nextClipOrder,
    });
    setSelectedClipId(clipId);
    setSelectedTrackId(resolvedTrackId);
  }, [applyEdit, dataRef, selectedTrackId, setSelectedClipId, setSelectedTrackId]);

  return {
    registerGenerationAsset,
    uploadImageGeneration,
    handleAssetDrop,
  };
}

import { useCallback, useEffect, useRef } from 'react';
import {
  getGenerationDropData,
  getMultiGenerationDropData,
  getDragType,
} from '@/shared/lib/dnd/dragDrop';
import { inferDragKind } from '@/tools/video-editor/lib/drop-position';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type { UseAssetManagementResult } from '@/tools/video-editor/hooks/useAssetManagement';
import type {
  TimelineApplyEdit,
  TimelineInvalidateAssetRegistry,
  TimelinePatchRegistry,
  TimelineRegisterAsset,
  TimelineUploadAsset,
} from '@/tools/video-editor/hooks/timeline-state-types';
import { type TimelineData } from '@/tools/video-editor/lib/timeline-data';
import {
  finalizeExternalDrop,
  handleAssetDrop,
  handleEffectLayerDrop,
  handleFileDrop,
  handleMultiGenerationDrop,
  handleSingleGenerationDrop,
  handleTextToolDrop,
  isGenerationDragType,
  type TimelineDropPosition,
} from '@/tools/video-editor/lib/external-drop-utils';
import { RafLoopDetector } from '@/tools/video-editor/lib/perf-diagnostics';
import type { TrackKind } from '@/tools/video-editor/types';
import { createAutoScroller } from '@/tools/video-editor/lib/auto-scroll';

async function dispatchTimelineDrop({
  event,
  dataRef,
  pendingOpsRef,
  dropPosition,
  selectedTrackId,
  applyEdit,
  patchRegistry,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
  registerGenerationAsset,
  uploadImageGeneration,
  dropAsset,
  handleAddTextAt,
}: {
  event: React.DragEvent<HTMLDivElement>;
  dataRef: React.MutableRefObject<TimelineData | null>;
  pendingOpsRef: React.MutableRefObject<number>;
  dropPosition: TimelineDropPosition;
  selectedTrackId: string | null;
  applyEdit: TimelineApplyEdit;
  patchRegistry: TimelinePatchRegistry;
  uploadAsset: TimelineUploadAsset;
  invalidateAssetRegistry: TimelineInvalidateAssetRegistry;
  resolveAssetUrl: (file: string) => Promise<string>;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  uploadImageGeneration: UseAssetManagementResult['uploadImageGeneration'];
  dropAsset: UseAssetManagementResult['handleAssetDrop'];
  handleAddTextAt?: (trackId: string, time: number) => void;
}) {
  const insertAtTop = Boolean(dropPosition.isNewTrackTop);

  if (event.dataTransfer.types.includes('text-tool')) {
    handleTextToolDrop({ dataRef, dropPosition, insertAtTop, handleAddTextAt });
    return;
  }

  if (event.dataTransfer.types.includes('effect-layer')) {
    handleEffectLayerDrop({ dataRef, dropPosition, insertAtTop, selectedTrackId, applyEdit });
    return;
  }

  if (await handleFileDrop({
    files: Array.from(event.dataTransfer.files),
    dataRef,
    pendingOpsRef,
    dropPosition,
    insertAtTop,
    selectedTrackId,
    applyEdit,
    patchRegistry,
    uploadAsset,
    invalidateAssetRegistry,
    resolveAssetUrl,
    registerGenerationAsset,
    uploadImageGeneration,
    dropAsset,
  })) {
    return;
  }

  const multiGenerationData = getMultiGenerationDropData(event);
  if (multiGenerationData?.length) {
    handleMultiGenerationDrop({
      generationItems: multiGenerationData,
      dataRef,
      dropPosition,
      insertAtTop,
      registerGenerationAsset,
      patchRegistry,
      dropAsset,
    });
    return;
  }

  const generationData = getGenerationDropData(event);
  if (generationData) {
    handleSingleGenerationDrop({
      generationData,
      dataRef,
      dropPosition,
      insertAtTop,
      registerGenerationAsset,
      dropAsset,
    });
    return;
  }

  handleAssetDrop({
    assetKey: event.dataTransfer.getData('asset-key'),
    assetKind: event.dataTransfer.getData('asset-kind') as TrackKind,
    dataRef,
    dropPosition,
    insertAtTop,
    selectedTrackId,
    dropAsset,
  });
}

export interface UseExternalDropArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  pendingOpsRef: React.MutableRefObject<number>;
  scale: number;
  scaleWidth: number;
  selectedTrackId: string | null;
  applyEdit: TimelineApplyEdit;
  patchRegistry: TimelinePatchRegistry;
  registerAsset: TimelineRegisterAsset;
  uploadAsset: TimelineUploadAsset;
  invalidateAssetRegistry: TimelineInvalidateAssetRegistry;
  resolveAssetUrl: (file: string) => Promise<string>;
  coordinator: DragCoordinator;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  uploadImageGeneration: UseAssetManagementResult['uploadImageGeneration'];
  handleAssetDrop: UseAssetManagementResult['handleAssetDrop'];
  handleAddTextAt?: (trackId: string, time: number) => void;
  onSeekToTime?: (time: number) => void;
}

export interface UseExternalDropResult {
  onTimelineDragOver: (event: React.DragEvent<HTMLDivElement>) => void;
  onTimelineDragLeave: (event: React.DragEvent<HTMLDivElement>) => void;
  onTimelineDrop: (event: React.DragEvent<HTMLDivElement>) => void;
}

export function useExternalDrop({
  dataRef,
  pendingOpsRef,
  selectedTrackId,
  applyEdit,
  patchRegistry,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
  coordinator,
  registerGenerationAsset,
  uploadImageGeneration,
  handleAssetDrop: dropAsset,
  handleAddTextAt,
  onSeekToTime,
}: UseExternalDropArgs): UseExternalDropResult {
  const externalDragFrameRef = useRef<number | null>(null);
  const autoScrollerRef = useRef<ReturnType<typeof createAutoScroller> | null>(null);
  const latestExternalDragRef = useRef<{
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
  } | null>(null);
  const latestExternalPositionRef = useRef<ReturnType<DragCoordinator['update']> | null>(null);

  const clearExternalDragState = useCallback(() => {
    if (externalDragFrameRef.current !== null) {
      window.cancelAnimationFrame(externalDragFrameRef.current);
      externalDragFrameRef.current = null;
    }
    autoScrollerRef.current?.stop();
    autoScrollerRef.current = null;
    latestExternalDragRef.current = null;
    latestExternalPositionRef.current = null;
    coordinator.end();
  }, [coordinator]);

  useEffect(() => {
    return () => {
      clearExternalDragState();
    };
  }, [clearExternalDragState]);

  const onTimelineDragOver = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    const dragType = getDragType(event);
    const types = Array.from(event.dataTransfer.types);
    if (!types.includes('asset-key')
      && !types.includes('text-tool')
      && !types.includes('effect-layer')
      && dragType !== 'file'
      && !isGenerationDragType(dragType)) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    event.currentTarget.dataset.dragOver = 'true';
    latestExternalDragRef.current = {
      clientX: event.clientX,
      clientY: event.clientY,
      sourceKind: inferDragKind(event),
    };
    if (!autoScrollerRef.current && coordinator.editAreaRef.current) {
      autoScrollerRef.current = createAutoScroller(coordinator.editAreaRef.current, (clientX, clientY) => {
        const currentDrag = latestExternalDragRef.current;
        if (!currentDrag) {
          return;
        }

        latestExternalPositionRef.current = coordinator.update({
          clientX,
          clientY,
          sourceKind: currentDrag.sourceKind,
        });
      });
    }
    autoScrollerRef.current?.update(event.clientX, event.clientY);

    if (externalDragFrameRef.current !== null) {
      return;
    }

    externalDragFrameRef.current = window.requestAnimationFrame(() => {
      RafLoopDetector.track('externalDrop');
      externalDragFrameRef.current = null;
      const currentDrag = latestExternalDragRef.current;
      if (!currentDrag) {
        return;
      }

      latestExternalPositionRef.current = coordinator.update({
        clientX: currentDrag.clientX,
        clientY: currentDrag.clientY,
        sourceKind: currentDrag.sourceKind,
      });
    });
  }, [coordinator]);

  const onTimelineDragLeave = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    delete event.currentTarget.dataset.dragOver;
    clearExternalDragState();
  }, [clearExternalDragState]);

  const onTimelineDrop = useCallback(async (event: React.DragEvent<HTMLDivElement>) => {
    const dropPosition = finalizeExternalDrop({
      event,
      coordinator,
      autoScrollerRef,
      externalDragFrameRef,
      latestExternalDragRef,
      latestExternalPositionRef,
    });
    await dispatchTimelineDrop({
      event,
      dataRef,
      pendingOpsRef,
      dropPosition,
      selectedTrackId,
      applyEdit,
      patchRegistry,
      uploadAsset,
      invalidateAssetRegistry,
      resolveAssetUrl,
      registerGenerationAsset,
      uploadImageGeneration,
      dropAsset,
      handleAddTextAt,
    });
    onSeekToTime?.(dropPosition.time);
  }, [
    applyEdit,
    coordinator,
    dataRef,
    dropAsset,
    invalidateAssetRegistry,
    pendingOpsRef,
    patchRegistry,
    registerGenerationAsset,
    resolveAssetUrl,
    selectedTrackId,
    handleAddTextAt,
    uploadAsset,
    uploadImageGeneration,
  ]);

  return {
    onTimelineDragOver,
    onTimelineDragLeave,
    onTimelineDrop,
  };
}

