/**
 * Shot-scoped image queries. Queries shot_generations JOIN generations.
 * Exports: useShotImages, useTimelineImages, useUnpositionedImages, useVideoOutputs.
 */

import { useQuery, useQueryClient, UseQueryResult } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { GenerationRow } from '@/domains/generation/types';
import { QUERY_PRESETS, STANDARD_RETRY, STANDARD_RETRY_DELAY } from '@/shared/lib/query/queryDefaults';
import { generationQueryKeys } from '@/shared/lib/queryKeys/generations';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import React from 'react';

import { mapShotGenerationToRow } from '@/shared/hooks/shots';
import {
  selectTimelineImages,
  selectUnpositionedImages,
  selectVideoOutputs,
} from '@/shared/lib/shotImageSelectors';

/** Loads all shot_generations (positioned + unpositioned) for a shot. */
const useAllShotGenerations = (
  shotId: string | null,
  options?: {
    // When true, prevents query from refetching during sensitive operations (drag, persist, etc.)
    disableRefetch?: boolean;
  }
): UseQueryResult<GenerationRow[]> => {
  const stableShotId = React.useMemo(() => shotId, [shotId]);
  const isEnabled = React.useMemo(() => {
    if (options?.disableRefetch) {
      return false;
    }
    return !!stableShotId;
  }, [stableShotId, options?.disableRefetch]);

  const queryClient = useQueryClient();

  const mainQuery = useQuery<GenerationRow[], Error>({
    queryKey: generationQueryKeys.byShot(stableShotId!),
    enabled: isEnabled,
    // Use realtimeBacked preset - data freshness from realtime + mutations
    // (invalidated by RealtimeProvider + useGenerationInvalidation)
    ...QUERY_PRESETS.realtimeBacked,
    // realtimeBacked provides staleTime: 30_000 — don't override to 0.
    // staleTime: 0 makes the query perpetually stale, which combined with React Query's
    // observer.setOptions() running every render causes a fetch→render→fetch loop.
    // refetchOnMount: 'always' ensures fresh data when opening a shot without the loop.
    refetchOnMount: 'always',
    retry: STANDARD_RETRY,
    // NOTE: Removed placeholderData: (previousData) => previousData
    // This was causing cross-shot data leakage - when navigating to a new shot,
    // the previous shot's images would briefly appear as "placeholder" data
    queryFn: async ({ signal }) => {
      // Query shot_generations with embedded generations data + primary variant
      // NOTE: Must specify FK explicitly to avoid ambiguous relationship error (PGRST201)
      // since there are two FKs between shot_generations and generations
      // We also fetch the primary_variant using the generations.primary_variant_id FK
      // to get the correct display URL (primary variant may differ from generation.location)
      const response = await supabase().from('shot_generations')
        .select(`
          id,
          generation_id,
          timeline_frame,
          metadata,
          generation:generations!shot_generations_generation_id_generations_id_fk (
            id,
            location,
            thumbnail_url,
            type,
            created_at,
            starred,
            name,
            based_on,
            params,
            primary_variant_id,
            primary_variant:generation_variants!generations_primary_variant_id_fkey (
              location,
              thumbnail_url
            )
          )
        `)
        .eq('shot_id', stableShotId!)
        .order('timeline_frame', { ascending: true, nullsFirst: false })
        .abortSignal(signal);

      if (response.error) {
        // Abort errors are expected during rapid invalidations - silently return cached data
        if (response.error.code === '20' || response.error.message?.includes('abort')) {
          const cachedData = queryClient.getQueryData<GenerationRow[]>(generationQueryKeys.byShot(stableShotId!));
          return cachedData || [];
        }
        normalizeAndPresentError(response.error, {
          context: 'useShotImages.queryFn',
          showToast: false,
          logData: { shotId: stableShotId },
        });
        throw response.error;
      }

      return (response.data || [])
        .map(mapShotGenerationToRow)
        .filter(Boolean) as GenerationRow[];
    },
    retryDelay: STANDARD_RETRY_DELAY,
  });

  return mainQuery as UseQueryResult<GenerationRow[]>;
};

/** Positioned, non-video images with valid location, sorted by timeline_frame. */
export const useTimelineImages = (
  shotId: string | null
): UseQueryResult<GenerationRow[]> => {
  const baseQuery = useAllShotGenerations(shotId);

  const filtered = React.useMemo(() => {
    if (!baseQuery.data) return undefined;

    return selectTimelineImages(baseQuery.data);
  }, [baseQuery.data]);

  return { ...baseQuery, data: filtered } as UseQueryResult<GenerationRow[]>;
};

/** Non-video images with no timeline_frame. */
export const useUnpositionedImages = (
  shotId: string | null
): UseQueryResult<GenerationRow[]> => {
  const baseQuery = useAllShotGenerations(shotId);

  const filtered = React.useMemo(() => {
    if (!baseQuery.data) return undefined;

    return selectUnpositionedImages(baseQuery.data);
  }, [baseQuery.data]);

  return { ...baseQuery, data: filtered } as UseQueryResult<GenerationRow[]>;
};

/** Video generations in the shot. */
export const useVideoOutputs = (
  shotId: string | null
): UseQueryResult<GenerationRow[]> => {
  const baseQuery = useAllShotGenerations(shotId);

  const filtered = React.useMemo(() => {
    if (!baseQuery.data) return undefined;

    return selectVideoOutputs(baseQuery.data);
  }, [baseQuery.data]);

  return { ...baseQuery, data: filtered } as UseQueryResult<GenerationRow[]>;
};

/** Seeds the shot-generations cache from ShotsContext for instant display on shot select. */
const usePrimeShotGenerationsCache = (
  shotId: string | null,
  contextImages: GenerationRow[] | undefined
) => {
  const queryClient = useQueryClient();

  React.useEffect(() => {
    if (!shotId || !contextImages || contextImages.length === 0) return;

    const existingData = queryClient.getQueryData<GenerationRow[]>(generationQueryKeys.byShot(shotId));
    if (existingData && existingData.length > 0) return;

    // Prime the cache with context data
    queryClient.setQueryData(generationQueryKeys.byShot(shotId), contextImages);
  }, [shotId, contextImages, queryClient]);
};

export const useShotImages = useAllShotGenerations;
export const usePrimeShotImagesCache = usePrimeShotGenerationsCache;

import React, { createContext, useContext, ReactNode, useMemo, useState, useEffect } from 'react';
import { useListShots, useProjectImageStats } from '@/shared/hooks/shots';
import { useProject } from '@/shared/contexts/ProjectContext';
import { Shot } from '@/domains/generation/types';

interface ShotsContextType {
  shots: Shot[] | undefined;
  isLoading: boolean;
  error: Error | null;
  refetchShots: () => void;
  // Stats for SHOT_FILTER.ALL and SHOT_FILTER.NO_SHOT filters
  allImagesCount?: number;
  noShotImagesCount?: number;
}

const ShotsContext = createContext<ShotsContextType | undefined>(undefined);

interface ShotsProviderProps {
  children: ReactNode;
}

export const ShotsProvider: React.FC<ShotsProviderProps> = ({ children }) => {
  const { selectedProjectId } = useProject();

  const [isProjectTransitioning, setIsProjectTransitioning] = useState(false);
  const prevProjectIdRef = React.useRef<string | null>(null);

  // Load all images per shot (0 = unlimited)
  // Previously limited to 2 on mobile for performance, but this broke expand/collapse UI
  const maxImagesPerShot = 0;

  const { data: shots, isLoading: isShotsLoading, isFetching: isShotsFetching, error: shotsError, refetch } = useListShots(selectedProjectId, { maxImagesPerShot });

  // Load project-wide image stats
  const { data: projectStats, isLoading: isStatsLoading } = useProjectImageStats(selectedProjectId);

  // Set transitioning flag when project changes
  useEffect(() => {
    if (prevProjectIdRef.current !== null && prevProjectIdRef.current !== selectedProjectId) {
      setIsProjectTransitioning(true);
    }
    prevProjectIdRef.current = selectedProjectId;
  }, [selectedProjectId]);

  // Clear transitioning flag when new data arrives
  useEffect(() => {
    if (isProjectTransitioning && !isShotsFetching && shots !== undefined) {
      setIsProjectTransitioning(false);
    }
  }, [isProjectTransitioning, isShotsFetching, shots]);

  // Show loading during transition or actual loading
  const isLoading = isShotsLoading || isStatsLoading || isProjectTransitioning;
  const error = shotsError;

  // Return undefined for shots during transition to force skeleton display
  // This prevents showing stale data from a previously cached project
  const effectiveShots = isProjectTransitioning ? undefined : shots;

  // Memoize context value to prevent unnecessary re-renders of consumers
  const value = useMemo<ShotsContextType>(() => ({
    shots: effectiveShots,
    isLoading,
    error,
    refetchShots: refetch,
    allImagesCount: projectStats?.allCount,
    noShotImagesCount: projectStats?.noShotCount,
  }), [effectiveShots, isLoading, error, refetch, projectStats]);

  return (
    <ShotsContext.Provider value={value}>
      {children}
    </ShotsContext.Provider>
  );
};

export const useShots = (): ShotsContextType => {
  const context = useContext(ShotsContext);
  if (context === undefined) {
    throw new Error('useShots must be used within a ShotsProvider');
  }
  return context;
};

/**
 * Shared utilities for drag-and-drop operations involving generations and shots
 *
 * Used by:
 * - MediaGalleryItem (drag source)
 * - ShotGroup, SortableShotItem, ShotListDisplay (drop targets)
 * - Timeline components (drop targets)
 * - BatchDropZone (drop target)
 */

import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';

// MIME type for generation drag data
const GENERATION_MIME_TYPE = 'application/x-generation';
const GENERATION_TEXT_PREFIX = '__reigh_generation__:';
export const GENERATION_MULTI_DRAG_TYPE = 'application/x-generation-multi';
const GENERATION_MULTI_TEXT_PREFIX = '__reigh_generation_multi__:';
const SHOT_MIME_TYPE = 'application/x-shot';
const SHOT_TEXT_PREFIX = '__reigh_shot__:';

// Droppable ID for creating a new shot from a dropped generation
export const NEW_GROUP_DROPPABLE_ID = 'new-shot-group-dropzone';

/**
 * Cross-browser safe check for whether a DataTransfer contains a type.
 */
function hasDataTransferType(dataTransfer: DataTransfer, type: string): boolean {
  const types = dataTransfer?.types;
  if (!types) return false;

  if (typeof types.includes === 'function') {
    try {
      return !!types.includes(type);
    } catch {
      // ignore
    }
  }

  const length = typeof types.length === 'number' ? types.length : 0;
  for (let i = 0; i < length; i += 1) {
    if (types[i] === type) return true;
  }

  return false;
}

/**
 * Data structure for dragging generations between components
 */
export interface GenerationDropData {
  generationId: string;
  variantId?: string;
  variantType?: string;
  imageUrl: string;
  thumbUrl?: string;
  metadata?: Record<string, unknown>;
}

export interface ShotDropData {
  shotId: string;
  shotName: string;
  imageGenerationIds: string[];
}

/**
 * Type of drag operation
 */
export type DragType = 'generation' | 'generation-multi' | 'shot' | 'file' | 'none';

function isMultiGenerationDrag(e: React.DragEvent): boolean {
  if (hasDataTransferType(e.dataTransfer, GENERATION_MULTI_DRAG_TYPE)) {
    return true;
  }

  if (!hasDataTransferType(e.dataTransfer, 'text/plain')) {
    return false;
  }

  const textPayload = e.dataTransfer.getData('text/plain');
  return parseMultiGenerationDropData(textPayload) !== null;
}

/**
 * Check if the drag event contains generation data.
 * @internal Used by getDragType.
 */
function isGenerationDrag(e: React.DragEvent): boolean {
  if (hasDataTransferType(e.dataTransfer, GENERATION_MIME_TYPE)) {
    return true;
  }

  if (!hasDataTransferType(e.dataTransfer, 'text/plain')) {
    return false;
  }

  const textPayload = e.dataTransfer.getData('text/plain');
  return parseGenerationDropData(textPayload) !== null;
}

function isShotDrag(e: React.DragEvent): boolean {
  if (hasDataTransferType(e.dataTransfer, SHOT_MIME_TYPE)) {
    return true;
  }

  if (!hasDataTransferType(e.dataTransfer, 'text/plain')) {
    return false;
  }

  const textPayload = e.dataTransfer.getData('text/plain');
  return parseShotDropData(textPayload) !== null;
}

/**
 * Check if the drag event contains files
 */
export function isFileDrag(e: React.DragEvent): boolean {
  return hasDataTransferType(e.dataTransfer, 'Files');
}

/**
 * Determine the type of drag operation
 */
export function getDragType(e: React.DragEvent): DragType {
  if (isMultiGenerationDrag(e)) return 'generation-multi';
  if (isGenerationDrag(e)) return 'generation';
  if (isShotDrag(e)) return 'shot';
  if (isFileDrag(e)) return 'file';
  return 'none';
}

/**
 * Set generation drag data on the dataTransfer object
 * Call this in onDragStart
 */
export function setGenerationDragData(e: React.DragEvent, data: GenerationDropData): void {
  const serialized = JSON.stringify(data);
  e.dataTransfer.effectAllowed = 'copy';
  e.dataTransfer.setData(GENERATION_MIME_TYPE, serialized);
  // Fallback: some browsers/targets are inconsistent about exposing custom MIME types during dragover.
  try {
    e.dataTransfer.setData('text/plain', `${GENERATION_TEXT_PREFIX}${serialized}`);
  } catch {
    // ignore
  }
}

export function setMultiGenerationDragData(
  e: React.DragEvent,
  items: GenerationDropData[],
): void {
  const serialized = JSON.stringify(items);
  e.dataTransfer.effectAllowed = 'copy';
  e.dataTransfer.setData(GENERATION_MULTI_DRAG_TYPE, serialized);
  try {
    e.dataTransfer.setData('text/plain', `${GENERATION_MULTI_TEXT_PREFIX}${serialized}`);
  } catch {
    // ignore
  }
}

export function setShotDragData(e: React.DragEvent, data: ShotDropData): void {
  const serialized = JSON.stringify(data);
  e.dataTransfer.effectAllowed = 'copy';
  e.dataTransfer.setData(SHOT_MIME_TYPE, serialized);
  try {
    e.dataTransfer.setData('text/plain', `${SHOT_TEXT_PREFIX}${serialized}`);
  } catch {
    // ignore
  }
}

function parseGenerationDropData(dataString: string): GenerationDropData | null {
  if (!dataString) {
    return null;
  }

  let data: GenerationDropData;
  try {
    const normalized = dataString.startsWith(GENERATION_TEXT_PREFIX)
      ? dataString.slice(GENERATION_TEXT_PREFIX.length)
      : dataString;
    data = JSON.parse(normalized) as GenerationDropData;
  } catch {
    return null;
  }

  if (!data.generationId || !data.imageUrl) {
    return null;
  }

  return data;
}

function parseMultiGenerationDropData(dataString: string): GenerationDropData[] | null {
  if (!dataString) {
    return null;
  }

  let data: unknown;
  try {
    const normalized = dataString.startsWith(GENERATION_MULTI_TEXT_PREFIX)
      ? dataString.slice(GENERATION_MULTI_TEXT_PREFIX.length)
      : dataString;
    data = JSON.parse(normalized);
  } catch {
    return null;
  }

  if (!Array.isArray(data) || data.length === 0) {
    return null;
  }

  const items = data
    .map((item) => parseGenerationDropData(JSON.stringify(item)))
    .filter((item): item is GenerationDropData => item !== null);

  return items.length === data.length ? items : null;
}

