}

function toRecord(value: unknown): Record<string, unknown> {
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }
  return {};
}

/**
 * Maps a raw Supabase response from shot_generations (with joined generations)
 * to the standardized GenerationRow format used throughout the app.
 *
 * IMPORTANT: This must be used by ALL hooks (useListShots, useShotImages, etc.)
 * to ensure selectors and filters work consistently across the Sidebar and Editor.
 */
export const mapShotGenerationToRow = (sg: RawShotGeneration): GenerationRow | null => {
  const gen = sg.generations || sg.generation; // Handle both aliases
  if (!gen) return null;

  // CRITICAL: Use primary variant's location/thumbnail if available
  // Falls back to generation.location if no primary variant exists (legacy data)
  const primaryVariant = gen.primary_variant;
  const effectiveLocation = primaryVariant?.location || gen.location;
  const effectiveThumbnail = primaryVariant?.thumbnail_url || gen.thumbnail_url || effectiveLocation;

  return {
    id: sg.id, // shot_generations.id (unique per entry in shot)
    generation_id: gen.id, // generations.id (the actual generation)

    // Deprecated aliases (kept for backwards compat during transition)
    shotImageEntryId: sg.id,
    shot_generation_id: sg.id,

    location: effectiveLocation,
    imageUrl: effectiveLocation,
    thumbUrl: effectiveThumbnail,
    type: gen.type || 'image',
    created_at: gen.created_at,
    createdAt: gen.created_at,
    starred: gen.starred || false,
    name: gen.name,
    based_on: gen.based_on,
    params: toRecord(gen.params),

    timeline_frame: sg.timeline_frame,
    metadata: toRecord(sg.metadata),
    primary_variant_id: gen.primary_variant_id || null,

    position: sg.timeline_frame != null ? Math.floor(sg.timeline_frame / 50) : undefined,
  } as GenerationRow;
};

import type { PersistedGenerationRow } from './generationRow';

/**
 * Derived display fields (read-only, produced by mappers/selectors from persisted data).
 * Ownership: mapper/query layer.
 */
interface GenerationDerivedFields {
  imageUrl?: string;
  thumbUrl?: string;
  contentType?: string;
  derivedCount?: number;
  hasUnviewedVariants?: boolean;
  unviewedVariantCount?: number;
}

/** Domain-facing generation contract = persisted row + derived view fields. */
export type GenerationRow = PersistedGenerationRow & GenerationDerivedFields;

function parseShotDropData(dataString: string): ShotDropData | null {
  if (!dataString) {
    return null;
  }

  let data: ShotDropData;
  try {
    const normalized = dataString.startsWith(SHOT_TEXT_PREFIX)
      ? dataString.slice(SHOT_TEXT_PREFIX.length)
      : dataString;
    data = JSON.parse(normalized) as ShotDropData;
  } catch {
    return null;
  }

  if (!data.shotId || typeof data.shotName !== 'string' || !Array.isArray(data.imageGenerationIds)) {
    return null;
  }

  if (!data.imageGenerationIds.every((generationId) => typeof generationId === 'string')) {
    return null;
  }

  return data;
}

/**
 * Get and parse generation drag data from the dataTransfer object
 * Call this in onDrop
 * Returns null if no valid data found
 */
export function getGenerationDropData(e: React.DragEvent): GenerationDropData | null {
  try {
    const dataString =
      e.dataTransfer.getData(GENERATION_MIME_TYPE) ||
      e.dataTransfer.getData('text/plain');
    return parseGenerationDropData(dataString);
  } catch (error) {
    normalizeAndPresentError(error, { context: 'DragDrop', showToast: false });
    return null;
  }
}

export function getMultiGenerationDropData(e: React.DragEvent): GenerationDropData[] | null {
  try {
    const dataString =
      e.dataTransfer.getData(GENERATION_MULTI_DRAG_TYPE) ||
      e.dataTransfer.getData('text/plain');
    return parseMultiGenerationDropData(dataString);
  } catch (error) {
    normalizeAndPresentError(error, { context: 'DragDrop', showToast: false });
    return null;
  }
}

export function getShotDropData(e: React.DragEvent): ShotDropData | null {
  try {
    const dataString =
      e.dataTransfer.getData(SHOT_MIME_TYPE) ||
      e.dataTransfer.getData('text/plain');
    return parseShotDropData(dataString);
  } catch (error) {
    normalizeAndPresentError(error, { context: 'DragDrop', showToast: false });
    return null;
  }
}

/**
 * Check if the drag event is a valid drop target (generation or file)
 */
export function isValidDropTarget(e: React.DragEvent): boolean {
  return isMultiGenerationDrag(e) || isGenerationDrag(e) || isFileDrag(e);
}

/**
 * Create a visual drag preview element
 * Returns a cleanup function to remove the element
 */
export function createDragPreview(
  e: React.DragEvent, 
  options?: { 
    size?: number; 
    borderColor?: string;
    badgeText?: string;
  }
): (() => void) | null {
  const { size = 80, borderColor = '#fff', badgeText } = options || {};

  if (!e.dataTransfer.setDragImage || !(e.currentTarget instanceof HTMLElement)) {
    return null;
  }

  const preview = document.createElement('div');
  preview.style.position = 'absolute';
  preview.style.top = '-1000px';
  preview.style.width = `${size}px`;
  preview.style.height = `${size}px`;
  preview.style.opacity = '0.7';
  preview.style.borderRadius = '8px';
  preview.style.overflow = 'hidden';
  preview.style.border = `2px solid ${borderColor}`;

