      dragSessionRef.current = {
        pointerId: event.pointerId,
        clipId,
        sourceRowId: rowId,
        sourceKind: sourceTrack.kind,
        draggedClipIds: validDraggedClipIds,
        clipOffsets,
        ctrlKey: event.ctrlKey,
        metaKey: event.metaKey,
