 33	export function reorderTracksByDirection(
 34	  tracks: TrackDefinition[],
 35	  trackId: string,
 36	  direction: -1 | 1,
 37	): TrackDefinition[] {
 38	  const index = tracks.findIndex((track) => track.id === trackId);
 39	  if (index < 0) {
 40	    return tracks;
 41	  }
 42	
 43	  const trackKind = tracks[index]?.kind;
 44	  let targetIndex = index + direction;
 45	  while (
 46	    targetIndex >= 0 &&
 47	    targetIndex < tracks.length &&
 48	    tracks[targetIndex]?.kind !== trackKind
 49	  ) {
 50	    targetIndex += direction;
 51	  }
 52	
 53	  if (targetIndex < 0 || targetIndex >= tracks.length) {
 54	    return tracks;
 55	  }
 56	
 57	  const nextTracks = [...tracks];
 58	  [nextTracks[index], nextTracks[targetIndex]] = [nextTracks[targetIndex], nextTracks[index]];
 59	  return nextTracks;
 60	}
