          shotId: 'shot-pinned',
          shotName: 'Pinned Shot',
          rowId: 'V1',
          rowIndex: 0,
          clipIds: ['clip-1'],
          color: '#22c55e',
          isPinned: true,
          mode: 'images',
        },
      ],
    });

    expect(container.innerHTML).toContain('border-dashed');
    expect(container.innerHTML).toContain('border-solid');
    expect(getByText('Pinned Shot')).toBeTruthy();
  });
});

