  it('updates pinnedShotGroupsOverride when moveClipToRow moves a pinned clip to another track', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('V2', 'visual'),
    ];
    const dataRef = {
      current: {
        rows: [
          { id: 'V1', actions: [{ id: 'clip-1', start: 0, end: 2, effectId: 'effect-clip-1' }] },
          { id: 'V2', actions: [] },
        ],
        tracks,
        meta: {
          'clip-1': { track: 'V1', clipType: 'hold', hold: 2 },
