import type {
  ResolvedTimelineConfig,
  TimelineClip,
  TimelineConfig,
  TrackDefinition,
} from '@/tools/video-editor/types';

export const TIMELINE_CLIP_FIELDS = [
  'id',
  'at',
  'track',
  'clipType',
  'asset',
  'from',
  'to',
  'speed',
  'hold',
  'volume',
  'x',
  'y',
  'width',
  'height',
  'cropTop',
  'cropBottom',
  'cropLeft',
  'cropRight',
  'opacity',
  'text',
  'entrance',
  'exit',
  'continuous',
  'transition',
  'effects',
] as const;

export type TimelineClipField = (typeof TIMELINE_CLIP_FIELDS)[number];

export const TRACK_DEFINITION_FIELDS = [
  'id',
  'kind',
  'label',
  'scale',
  'fit',
  'opacity',
  'volume',
  'muted',
  'blendMode',
] as const;

export type TrackDefinitionField = (typeof TRACK_DEFINITION_FIELDS)[number];

export const serializeClipForDisk = (clip: ResolvedTimelineConfig['clips'][number]): TimelineClip => {
  const serializedClip: Partial<Record<TimelineClipField, TimelineClip[TimelineClipField]>> = {
    id: clip.id,
    at: clip.at,
    track: clip.track,
  };

  if (clip.asset !== undefined) {
    serializedClip.asset = clip.asset;
  }

  for (const field of TIMELINE_CLIP_FIELDS) {
    if (field in serializedClip) {
      continue;
    }

    const value = clip[field];
    if (value !== undefined) {
      serializedClip[field] = value;
    }
  }

  return serializedClip as TimelineClip;
};

export const serializeTrackForDisk = (track: TrackDefinition): TrackDefinition => {
  const serializedTrack: Partial<Record<TrackDefinitionField, TrackDefinition[TrackDefinitionField]>> = {
    id: track.id,
    kind: track.kind,
    label: track.label,
  };

  for (const field of TRACK_DEFINITION_FIELDS) {
    if (field in serializedTrack) {
      continue;
    }

    const value = track[field];
    if (value !== undefined) {
      serializedTrack[field] = value;
    }
  }

  return serializedTrack as TrackDefinition;
};

const ALLOWED_TOP_LEVEL_KEYS = new Set(['output', 'clips', 'tracks', 'customEffects', 'pinnedShotGroups']);

export const validateSerializedConfig = (config: TimelineConfig): void => {
  const topLevelKeys = Object.keys(config);
  const unexpectedKeys = topLevelKeys.filter((key) => !ALLOWED_TOP_LEVEL_KEYS.has(key));
  if (unexpectedKeys.length > 0) {
    throw new Error(`Serialized timeline has unexpected top-level keys: ${unexpectedKeys.join(', ')}`);
  }

  const allowedClipKeys = new Set<string>(TIMELINE_CLIP_FIELDS);
  for (const clip of config.clips) {
    const invalidClipKeys = Object.keys(clip).filter((key) => !allowedClipKeys.has(key));
    if (invalidClipKeys.length > 0) {
      throw new Error(`Serialized clip '${clip.id}' has unexpected keys: ${invalidClipKeys.join(', ')}`);
    }
  }

  const allowedTrackKeys = new Set<string>(TRACK_DEFINITION_FIELDS);
  for (const track of config.tracks ?? []) {
    const invalidTrackKeys = Object.keys(track).filter((key) => !allowedTrackKeys.has(key));
    if (invalidTrackKeys.length > 0) {
      throw new Error(`Serialized track '${track.id}' has unexpected keys: ${invalidTrackKeys.join(', ')}`);
    }
  }
};

export const serializeForDisk = (
  resolved: ResolvedTimelineConfig,
  customEffects?: TimelineConfig['customEffects'],
  pinnedShotGroups?: TimelineConfig['pinnedShotGroups'],
): TimelineConfig => {
  const serialized: TimelineConfig = {
    output: { ...resolved.output },
    tracks: resolved.tracks.map(serializeTrackForDisk),
    clips: resolved.clips.map(serializeClipForDisk),
  };

  if (customEffects && Object.keys(customEffects).length > 0) {
    serialized.customEffects = customEffects;
  }

  if (pinnedShotGroups && pinnedShotGroups.length > 0) {
    serialized.pinnedShotGroups = pinnedShotGroups;
  }

  validateSerializedConfig(serialized);
  return serialized;
};

import { describe, expect, it } from 'vitest';
import { serializeForDisk, validateSerializedConfig } from '@/tools/video-editor/lib/serialize';
import type { ResolvedTimelineConfig } from '@/tools/video-editor/types';

describe('video-editor serialization', () => {
  it('preserves exact source fields and strips resolved-only data', () => {
    const resolved = {
      output: {
        resolution: '1280x720',
        fps: 30,
        file: 'out.mp4',
        background_scale: 1,
      },
      tracks: [
        {
          id: 'V1',
          kind: 'visual',
          label: 'V1',
          scale: 1,
          fit: 'manual',
          opacity: 1,
          blendMode: 'normal',
          extra: 'strip-me',
        },
      ],
      clips: [
        {
          id: 'clip-1',
          at: 1,
          track: 'V1',
          clipType: 'hold',
          asset: 'asset-1',
          hold: 5,
          opacity: 0.8,
          transition: { type: 'crossfade', duration: 0.4 },
          continuous: { type: 'custom:glow', intensity: 0.6 },
          assetEntry: { file: 'foo.png', src: 'https://example.com/foo.png' },
          extra: 'strip-me',
        },
      ],
      registry: {
        'asset-1': { file: 'foo.png', src: 'https://example.com/foo.png' },
      },
    } as unknown as ResolvedTimelineConfig;

    const serialized = serializeForDisk(resolved, {
      glow: { code: 'export default function Effect(){ return null; }', category: 'continuous' },
    });

    expect(serialized.output.background_scale).toBe(1);
    expect(serialized.customEffects).toEqual({
      glow: { code: 'export default function Effect(){ return null; }', category: 'continuous' },
    });
    expect(serialized.clips[0]).not.toHaveProperty('assetEntry');
    expect(serialized.clips[0]).not.toHaveProperty('extra');
    expect(serialized.tracks?.[0]).not.toHaveProperty('extra');
    expect(() => validateSerializedConfig(serialized)).not.toThrow();
  });

  it('round-trips pinnedShotGroups through serializeForDisk and validation', () => {
    const resolved = {
      output: {
        resolution: '1280x720',
        fps: 30,
        file: 'out.mp4',
      },
      tracks: [
        {
          id: 'V1',
          kind: 'visual',
          label: 'V1',
        },
      ],
      clips: [
        {
          id: 'clip-1',
          at: 0,
          track: 'V1',
          clipType: 'hold',
          asset: 'asset-1',
          hold: 5,
        },
      ],
      registry: {
        'asset-1': { file: 'foo.png', src: 'https://example.com/foo.png' },
      },
    } as unknown as ResolvedTimelineConfig;

    const pinnedShotGroups = [
      {
        shotId: 'shot-1',
        trackId: 'V1',
        clipIds: ['clip-1'],
        mode: 'images' as const,
        imageClipSnapshot: [
          {
            clipId: 'clip-1',
            assetKey: 'asset-1',
            meta: {
              clipType: 'hold' as const,
              hold: 5,
            },
          },
        ],
      },
    ];

    const serialized = serializeForDisk(resolved, undefined, pinnedShotGroups);

    expect(() => validateSerializedConfig(serialized)).not.toThrow();
    expect(serialized.pinnedShotGroups).toEqual(pinnedShotGroups);
  });
});
